import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e}from"./app-744a1728.js";const t={},p=e(`<p>연산자(Operator)는 하나 이상의 표현식을 대상으로, 산술, 할당, 비교, 논리, 타입, 지수 연산 등을 수행해 하나의 값을 만든다.</p><p>이때 연산의 대상을 피연산자(Operand)라 한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 산술 연산자</span>
<span class="token number">5</span> <span class="token operator">*</span> <span class="token number">4</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; 20</span>

<span class="token comment">// 문자열 연결 연산자</span>
<span class="token string">&quot;My name is &quot;</span> <span class="token operator">+</span> <span class="token string">&quot;Lee&quot;</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; &#39;My name is Lee&#39;</span>

<span class="token comment">// 할당 연산자</span>
color <span class="token operator">=</span> <span class="token string">&quot;red&quot;</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; &#39;red&#39;</span>

<span class="token comment">// 비교 연산자</span>
<span class="token number">3</span> <span class="token operator">&gt;</span> <span class="token number">5</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; false</span>

<span class="token comment">// 논리 연산자</span>
<span class="token boolean">true</span> <span class="token operator">&amp;&amp;</span> <span class="token boolean">false</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>

<span class="token comment">// 타입 연산자</span>
<span class="token keyword">typeof</span> <span class="token string">&quot;Hi&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; string</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>연산자는 값으로 평가된 피연산자를 연산해 새로운 값을 만든다.</p><h2 id="_1-산술-연산자" tabindex="-1"><a class="header-anchor" href="#_1-산술-연산자" aria-hidden="true">#</a> 1. 산술 연산자</h2><p>산술연산자는 피연산자를 대상으로 수학적 계산을 수행해 새로운 숫자 값을 만든다.<br> 연산이 불가능한 경우 <code>NaN</code>을 반환한다.<br> 산술 연산자는 피연산자의 개수에 따라 이항 산술 연산자와 단항 산술 연산자로 구분할 수 있다.</p><h3 id="_1-1-이항-산술-연산자" tabindex="-1"><a class="header-anchor" href="#_1-1-이항-산술-연산자" aria-hidden="true">#</a> 1.1. 이항 산술 연산자</h3><p>이항 산술 연산자는 2개의 피연산자를 산술 연산하여 숫자 값을 만든다.</p><table><thead><tr><th style="text-align:center;">이항 산술 연산자</th><th style="text-align:left;">의미</th></tr></thead><tbody><tr><td style="text-align:center;">+</td><td style="text-align:left;">덧셈</td></tr><tr><td style="text-align:center;">-</td><td style="text-align:left;">뺄셈</td></tr><tr><td style="text-align:center;">*</td><td style="text-align:left;">곱셈</td></tr><tr><td style="text-align:center;">/</td><td style="text-align:left;">나눗셈</td></tr><tr><td style="text-align:center;">%</td><td style="text-align:left;">나머지</td></tr></tbody></table><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token number">5</span> <span class="token operator">/</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 2.5</span>
<span class="token number">5</span> <span class="token operator">%</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; 1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-2-단항-산술-연산자" tabindex="-1"><a class="header-anchor" href="#_1-2-단항-산술-연산자" aria-hidden="true">#</a> 1.2. 단항 산술 연산자</h3><p>단항 산술 연산자는 1개의 피연산자를 산술 연산하여 숫자 값을 만든다.</p><table><thead><tr><th style="text-align:center;">단항 산술 연산자</th><th style="text-align:left;">의미</th><th style="text-align:center;">부수 효과</th></tr></thead><tbody><tr><td style="text-align:center;">++</td><td style="text-align:left;">증가</td><td style="text-align:center;">O</td></tr><tr><td style="text-align:center;">--</td><td style="text-align:left;">감소</td><td style="text-align:center;">O</td></tr><tr><td style="text-align:center;">+</td><td style="text-align:left;">어떠한 효과도 없다. 음수를 양수로 반전하지도 않는다.</td><td style="text-align:center;">X</td></tr><tr><td style="text-align:center;">-</td><td style="text-align:left;">양수를 음수로, 음수를 양수로 반전한 값을 반환한다.</td><td style="text-align:center;">X</td></tr></tbody></table><p>이항 산술 연산자와는 달리 증가/감소(++/--) 연산자는 피연산자의 값을 변경하는 암묵적인 할당이 이뤄진다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

x<span class="token operator">++</span><span class="token punctuation">;</span> <span class="token comment">// x = x + 1</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 2</span>

x<span class="token operator">--</span><span class="token punctuation">;</span> <span class="token comment">// x = x - 1</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>증가/감소(++/--) 연산자는 위치에 의미가 있다</p><ul><li>피연산자 앞에 위치하면 먼저 피연산자의 값을 변경한 후, 다른 연산을 수행한다</li><li>피연산자 뒤에 위치하면 먼저 다른 연산을 수행한 후, 피연산자의 값을 변경한다.</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">5</span><span class="token punctuation">,</span>
  result<span class="token punctuation">;</span>

result <span class="token operator">=</span> x<span class="token operator">++</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>result<span class="token punctuation">,</span> x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 5 6</span>

result <span class="token operator">=</span> <span class="token operator">++</span>x<span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>result<span class="token punctuation">,</span> x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 7 7</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-3-문자열-연결-연산자" tabindex="-1"><a class="header-anchor" href="#_1-3-문자열-연결-연산자" aria-hidden="true">#</a> 1.3. 문자열 연결 연산자</h3><p><code>+</code> 연산자는 피연산자 중 하나 이상이 문자열인 경우 문자열 연결 연산자로 동작한다</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">//문자열 연결 연산자</span>
<span class="token string">&quot;1&quot;</span> <span class="token operator">+</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; &#39;12&#39;</span>
<span class="token number">1</span> <span class="token operator">+</span> <span class="token string">&quot;2&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &#39;12&#39;</span>

<span class="token comment">// 산술 연산자</span>
<span class="token number">1</span> <span class="token operator">+</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 3</span>

<span class="token comment">// true는 1로 타입 변환</span>
<span class="token number">1</span> <span class="token operator">+</span> <span class="token boolean">true</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 2</span>

<span class="token comment">// false는 0으로 타입 변환</span>
<span class="token number">1</span> <span class="token operator">+</span> <span class="token boolean">false</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; 1</span>

<span class="token comment">// null은 0으로 타입 변환</span>
<span class="token number">1</span> <span class="token operator">+</span> <span class="token keyword">null</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; 1</span>

<span class="token comment">//undefined는 숫자로 타입 변환되지 않는다</span>
<span class="token number">1</span> <span class="token operator">+</span> <span class="token keyword">undefined</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; NaN</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>개발자의 의도와는 상관없이 자바스크립트 엔진에 의해 암묵적으로 타입이 자동 변환된다.<br> 이를 암묵적 타입변환 또는 타입 강제 변환이라고 한다.</p><h2 id="_2-할당-연산자" tabindex="-1"><a class="header-anchor" href="#_2-할당-연산자" aria-hidden="true">#</a> 2. 할당 연산자</h2><p>할당 연산자는 우항에 있는 피연산자의 평가 결과를 좌항에 있는 변수에 할당한다.<br> 좌항의 변수에 값을 할당하므로 변수 값이 변하는 부수효과가 있다.</p><table><thead><tr><th style="text-align:center;">할당 연산자</th><th style="text-align:left;">예</th><th style="text-align:left;">동일 표현</th></tr></thead><tbody><tr><td style="text-align:center;">=</td><td style="text-align:left;">x = 5</td><td style="text-align:left;">x = 5</td></tr><tr><td style="text-align:center;">+=</td><td style="text-align:left;">x += 5</td><td style="text-align:left;">x = x + 5</td></tr><tr><td style="text-align:center;">-=</td><td style="text-align:left;">x -= 5</td><td style="text-align:left;">x = x - 5</td></tr><tr><td style="text-align:center;">*=</td><td style="text-align:left;">x *= 5</td><td style="text-align:left;">x = x * 5</td></tr><tr><td style="text-align:center;">/=</td><td style="text-align:left;">x /= 5</td><td style="text-align:left;">x = x / 5</td></tr><tr><td style="text-align:center;">%=</td><td style="text-align:left;">x %= 5</td><td style="text-align:left;">x = x % 5</td></tr></tbody></table><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> str <span class="token operator">=</span> <span class="token string">&quot;My name is&quot;</span><span class="token punctuation">;</span>

str <span class="token operator">+=</span> <span class="token string">&quot;Lee&quot;</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>str<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &#39;My name is Lee&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>할당문은 값으로 평가되는 표현식인 문으로서 할당된 값으로 평가된다.<br> 이러한 특징을 활용해 여러 변수에 동일한 값을 연쇄 할당할 수 있다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">;</span>

a <span class="token operator">=</span> b <span class="token operator">=</span> c <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_3-비교-연산자" tabindex="-1"><a class="header-anchor" href="#_3-비교-연산자" aria-hidden="true">#</a> 3. 비교 연산자</h2><p>비교 연산자는 좌항과 우항의 피연산자를 비교한 다음 그 결과를 불리언 값으로 반환한다.</p><h3 id="_3-1-동등-일치-비교-연산자" tabindex="-1"><a class="header-anchor" href="#_3-1-동등-일치-비교-연산자" aria-hidden="true">#</a> 3.1. 동등/일치 비교 연산자</h3><p>동등 비교 연산자와 일치 비교 연산자는 좌항과 우항의 피연산자가 같은 값으로 평가되는지 비교해 불리언 값을 반환한다.</p><table><thead><tr><th style="text-align:center;">비교 연산자</th><th style="text-align:center;">의미</th><th style="text-align:center;">예시</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:center;">==</td><td style="text-align:center;">동등 비교</td><td style="text-align:center;">x == y</td><td style="text-align:left;">x와 y의 값이 같음</td></tr><tr><td style="text-align:center;">===</td><td style="text-align:center;">일치 비교</td><td style="text-align:center;">x === y</td><td style="text-align:left;">x와 y의 값과 타입이 같음</td></tr><tr><td style="text-align:center;">!=</td><td style="text-align:center;">부동등 비교</td><td style="text-align:center;">x != y</td><td style="text-align:left;">x와 y의 값이 다름</td></tr><tr><td style="text-align:center;">!==</td><td style="text-align:center;">불일치 비교</td><td style="text-align:center;">x !== y</td><td style="text-align:left;">x와 y의 값과 타입이 다름</td></tr></tbody></table><p>동등 비교(==) 연산자는 <strong>먼저 암묵적 타입 변환을 통해 타입을 일치 시킨 후 같은 값인지 비교</strong>한다.</p><p>암묵적 타입 변환 후에 같은 값일 수 있다면 <code>true</code>를 반환한다</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 동등 비교</span>
<span class="token number">5</span> <span class="token operator">==</span> <span class="token number">5</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>

<span class="token comment">// 타입은 다르지만 암묵적 타입 변환을 통해 타입을 일치시키면 동등하다</span>
<span class="token number">5</span> <span class="token operator">==</span> <span class="token string">&quot;5&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>일치 비교(===) 연산자는 <strong>타입도 같고 값도 같은 경우</strong>에 한하여 <code>true</code>를 반환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token number">5</span> <span class="token operator">===</span> <span class="token number">5</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>

<span class="token number">5</span> <span class="token operator">===</span> <span class="token string">&quot;5&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>일치 비교 연산자에서 주의할 것은 <code>NaN</code>이다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token number">NaN</span> <span class="token operator">===</span> <span class="token number">NaN</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>NaN</code>은 자신과 일치하지 않은 유일한 값이다.<br> 따라서 숫자가 <code>NaN</code>인지 조사하려면 <code>Number.isNaN</code>을 사용한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>Number<span class="token punctuation">.</span><span class="token function">isNaN</span><span class="token punctuation">(</span><span class="token number">NaN</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
Number<span class="token punctuation">.</span><span class="token function">isNaN</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>
Number<span class="token punctuation">.</span><span class="token function">isNaN</span><span class="token punctuation">(</span><span class="token number">1</span> <span class="token operator">+</span> <span class="token keyword">undefined</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="object-is-메서드" tabindex="-1"><a class="header-anchor" href="#object-is-메서드" aria-hidden="true">#</a> <code>Object.is</code> 메서드</h3><p>ES6에서 도입된 <code>Object.is</code> 메서드는 다음과 같이 예측 가능한 정확한 비교 결과를 반환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token operator">-</span><span class="token number">0</span> <span class="token operator">===</span> <span class="token operator">+</span><span class="token number">0</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
Object<span class="token punctuation">.</span><span class="token function">is</span><span class="token punctuation">(</span><span class="token operator">-</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token operator">+</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>

<span class="token number">NaN</span> <span class="token operator">===</span> <span class="token number">NaN</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>
Object<span class="token punctuation">.</span><span class="token function">is</span><span class="token punctuation">(</span><span class="token number">NaN</span><span class="token punctuation">,</span> <span class="token number">NaN</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>부동등 비교 연산자(!=)와 불일치 비교 연산자(!==)는 각각 동등 비교(==) 연산자와 일치 비교(===) 연산자의 반대 개념이다.</p><h3 id="_3-2-대소-관계-비교-연산자" tabindex="-1"><a class="header-anchor" href="#_3-2-대소-관계-비교-연산자" aria-hidden="true">#</a> 3.2. 대소 관계 비교 연산자</h3><p>대소 관계 비교 연산자는 피연산자의 크기를 비교하여 불리언 값을 반환한다</p><table><thead><tr><th style="text-align:center;">대소 관계 비교 연산자</th><th style="text-align:center;">예제</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:center;">&gt;</td><td style="text-align:center;">x &gt; y</td><td style="text-align:left;">x가 y보다 크다</td></tr><tr><td style="text-align:center;">&lt;</td><td style="text-align:center;">x &lt; y</td><td style="text-align:left;">x가 y보다 작다</td></tr><tr><td style="text-align:center;">&gt;=</td><td style="text-align:center;">x &gt;= y</td><td style="text-align:left;">x가 y보다 크거나 같다</td></tr><tr><td style="text-align:center;">&lt;=</td><td style="text-align:center;">x &lt;= y</td><td style="text-align:left;">x가 y보다 작거나 같다</td></tr></tbody></table><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token number">5</span> <span class="token operator">&gt;</span> <span class="token number">0</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
<span class="token number">5</span> <span class="token operator">&gt;</span> <span class="token number">5</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; false</span>
<span class="token number">5</span> <span class="token operator">&gt;=</span> <span class="token number">5</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; true</span>
<span class="token number">5</span> <span class="token operator">&lt;=</span> <span class="token number">5</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_4-삼항-조건-연산자" tabindex="-1"><a class="header-anchor" href="#_4-삼항-조건-연산자" aria-hidden="true">#</a> 4. 삼항 조건 연산자</h2><p>삼항 조건 연산자는 조건식의 평가 결과에 따라 반환할 값을 결정한다.</p><img width="829" alt="" src="https://github.com/Zamoca42/blog/assets/96982072/f4ed416d-cfee-4460-a41b-a9f0c0db28be"><p>물음표(?) 앞의 첫 번째 피연산자는 조건식이고 조건식이 참이면 콜론(:) 앞의 두 번째 피연산자가 평가되어 반환되고,</p><p>거짓이면 콜론(:) 뒤의 세 번째 피연산자가 평가되어 반환된다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">;</span>

<span class="token keyword">var</span> result <span class="token operator">=</span> x <span class="token operator">%</span> <span class="token number">2</span> <span class="token operator">?</span> <span class="token string">&quot;홀수&quot;</span> <span class="token operator">:</span> <span class="token string">&quot;짝수&quot;</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>result<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 짝수</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_5-논리-연산자" tabindex="-1"><a class="header-anchor" href="#_5-논리-연산자" aria-hidden="true">#</a> 5. 논리 연산자</h2><p>논리 연산자는 우항과 좌항의 피연산자(부정 논리 연산자의 경우 우항의 피연산자)를 논리 연산한다.</p><table><thead><tr><th style="text-align:center;">논리 연산자</th><th style="text-align:left;">의미</th></tr></thead><tbody><tr><td style="text-align:center;">||</td><td style="text-align:left;">논리합(OR)</td></tr><tr><td style="text-align:center;">&amp;&amp;</td><td style="text-align:left;">논리곱(AND)</td></tr><tr><td style="text-align:center;">!</td><td style="text-align:left;">부정(NOT)</td></tr></tbody></table><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 논리합(||) 연산자</span>
<span class="token boolean">true</span> <span class="token operator">||</span> <span class="token boolean">true</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
<span class="token boolean">true</span> <span class="token operator">||</span> <span class="token boolean">false</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
<span class="token boolean">false</span> <span class="token operator">||</span> <span class="token boolean">false</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>

<span class="token comment">// 논리곱(&amp;&amp;) 연산자</span>
<span class="token boolean">true</span> <span class="token operator">&amp;&amp;</span> <span class="token boolean">true</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
<span class="token boolean">false</span> <span class="token operator">&amp;&amp;</span> <span class="token boolean">true</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>
<span class="token boolean">false</span> <span class="token operator">&amp;&amp;</span> <span class="token boolean">false</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>

<span class="token comment">// 논리 부정(!) 연산자</span>
<span class="token operator">!</span><span class="token boolean">true</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>
<span class="token operator">!</span><span class="token boolean">false</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>논리 부정(!) 연산자는 언제나 불리언 값을 반환한다.<br> 만약 불리언값이 아니면 불리언 타입으로 암묵적 타입 변환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token operator">!</span><span class="token number">0</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
<span class="token operator">!</span><span class="token string">&quot;Hello&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>논리합(||)또는 논리곱(&amp;&amp;) 연산자 표현식은 평가 결과가 불리언 값이 아닐 때 2개의 피연산자 중 어느 한쪽으로 평가된다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token string">&quot;Cat&quot;</span> <span class="token operator">&amp;&amp;</span> <span class="token string">&quot;Dog&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &#39;Dog&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="_6-쉼표-연산자" tabindex="-1"><a class="header-anchor" href="#_6-쉼표-연산자" aria-hidden="true">#</a> 6. 쉼표 연산자</h2><p>쉼표(,) 연산자는 왼쪽부터 차례대로 피연산자를 평가하고 마지막 피연산의 평가가 끝나면 마지막 피연산자의 평가 결과를 반환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> x<span class="token punctuation">,</span> y<span class="token punctuation">,</span> z<span class="token punctuation">;</span>

<span class="token punctuation">(</span>x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token punctuation">(</span>y <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token punctuation">(</span>z <span class="token operator">=</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 3</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_7-그룹-연산자" tabindex="-1"><a class="header-anchor" href="#_7-그룹-연산자" aria-hidden="true">#</a> 7. 그룹 연산자</h2><p>소괄호(<code>()</code>)로 피연산자를 감싸는 그룹 연산자는 자신의 피연산자인 표현식을 가장 먼저 평가한다.<br> 그룹 연산자를 사용하면 연산자의 우선순위를 조절할 수 있다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token number">10</span> <span class="token operator">*</span> <span class="token number">2</span> <span class="token operator">+</span> <span class="token number">3</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 23</span>

<span class="token number">10</span> <span class="token operator">*</span> <span class="token punctuation">(</span><span class="token number">2</span> <span class="token operator">+</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 50</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>첫 번째 문에서는 수학에서 마찬가지로 10 * 2를 먼저 연산하고 20 + 3을 연산한다.<br> 두 번째 문에서는 그룹 연산자로 감싼 표현식을 먼저 연산한다.</p><h2 id="_8-typeof-연산자" tabindex="-1"><a class="header-anchor" href="#_8-typeof-연산자" aria-hidden="true">#</a> 8. typeof 연산자</h2><p><code>typeof</code> 연산자는 피연산자의 데이터 타입을 문자열로 반환한다.<br><code>null</code>을 반환하는 경우는 없으며, 함수의 경우 <code>function</code>을 반환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">typeof</span> <span class="token number">NaN</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; number</span>
<span class="token keyword">typeof</span> <span class="token keyword">null</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; object</span>
<span class="token keyword">typeof</span> <span class="token keyword">new</span> <span class="token class-name">Date</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; object</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>이처럼 <code>typeof</code>연산자가 반환하는 문자열은 7개의 데이터 타입과 정확히 일치하지는 않는다.<br><code>typeof</code> 연산자로 <code>null</code> 값을 연산해보면 <code>null</code>이 아닌 <code>object</code>를 반환한다는데 주의하자.</p><p>값이 <code>null</code>타입인지 확인할 때는 <code>typeof</code>대신 일치 연산자(===)를 사용하자.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> foo <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>

<span class="token keyword">typeof</span> foo <span class="token operator">===</span> <span class="token keyword">null</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>
foo <span class="token operator">===</span> <span class="token keyword">null</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>선언하지 않은 변수를 <code>typeof</code> 연산자로 연산해보면 <code>ReferenceError</code>가 발생하지 않고 <code>undefined</code>를 반환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">typeof</span> undecalred<span class="token punctuation">;</span> <span class="token comment">//-&gt; undefined</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="_9-지수-연산자" tabindex="-1"><a class="header-anchor" href="#_9-지수-연산자" aria-hidden="true">#</a> 9. 지수 연산자</h2><p>ES7에서 도입된 지수 연산자는 좌항의 피연산자를 밑(base)으로,<br> 우항의 피연산자를 지수(exponent)로 거듭 제곱하여 숫자 값을 반환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token number">2</span> <span class="token operator">**</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 4</span>
<span class="token number">2</span> <span class="token operator">**</span> <span class="token number">2.5</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; 5.65685...</span>
<span class="token number">2</span> <span class="token operator">**</span> <span class="token number">0</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 1</span>
<span class="token number">2</span> <span class="token operator">**</span> <span class="token operator">-</span><span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; 0.25</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>음수를 거듭제곱의 밑으로 사용해 계산하려면 다음과 같이 괄호로 묶어야한다</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token operator">-</span><span class="token number">5</span> <span class="token operator">**</span> <span class="token number">2</span> <span class="token comment">//-&gt; SyntaxError</span>

<span class="token punctuation">(</span><span class="token operator">-</span><span class="token number">5</span><span class="token punctuation">)</span> <span class="token operator">**</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 25</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>지수 연산자는 다른 산술 연산자와 마찬가지로 할당 연산자와 함께 사용할 수 있다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> num <span class="token operator">=</span> <span class="token number">5</span><span class="token punctuation">;</span>

num <span class="token operator">**=</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; 25</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>지수 연산자는 이항 연산자 중에서 우선순위가 가장 높다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token number">2</span> <span class="token operator">*</span> <span class="token number">5</span> <span class="token operator">**</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 50</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="_10-그-외의-연산자" tabindex="-1"><a class="header-anchor" href="#_10-그-외의-연산자" aria-hidden="true">#</a> 10. 그 외의 연산자</h2><table><thead><tr><th style="text-align:left;">연산자</th><th style="text-align:left;">개요</th></tr></thead><tbody><tr><td style="text-align:left;">?.</td><td style="text-align:left;">옵셔널 체이닝 연산자</td></tr><tr><td style="text-align:left;">??</td><td style="text-align:left;">null 병합 연산자</td></tr><tr><td style="text-align:left;">delete</td><td style="text-align:left;">프로퍼티 삭제</td></tr><tr><td style="text-align:left;">new</td><td style="text-align:left;">생성자 함수를 호출할 때 사용하여 인스턴스를 생성</td></tr><tr><td style="text-align:left;">instanceof</td><td style="text-align:left;">좌변의 객체가 우변의 생성자 함수와 연결된 인스턴스인지 판별</td></tr><tr><td style="text-align:left;">in</td><td style="text-align:left;">프로퍼티 존재 확인</td></tr></tbody></table>`,90),l=[p];function o(c,i){return s(),a("div",null,l)}const u=n(t,[["render",o],["__file","deepdive7.html.vue"]]);export{u as default};
